+// ─── Tool content handler (full-content fetch for truncated results) ────────
+
+function handleToolContentResponse(
+	msg: Extract<RelayMessage, { type: "tool_content" }>,
+): void {
+	const { toolId, content } = msg;
+	const messages = [...chatState.messages];
+	const idx = messages.findIndex(
+		(m) => m.type === "tool" && (m as ToolMessage).id === toolId,
+	);
+	if (idx >= 0) {
+		chatState.messages = messages.map((m, i) =>
+			i === idx
+				? {
+						...(m as ToolMessage),
+						result: content,
+						isTruncated: false,
+						fullContentLength: undefined,
+					}
+				: m,
+		);
+	}
+}
